def compute_stats(data, display=False, label="processed"):
    """
    Consolidated stats function.
    - If display is False (default), returns raw stats with keys:
      {"raw_mean", "raw_max", "raw_min", "raw_range"}
    - If display is True, returns display-friendly stats with keys:
      {"avg", "peak", "label"} (avg and peak are rounded to 1 decimal)
    Handles empty data by returning zeros for numeric fields.
    """
    if not data:
        if display:
            return {"avg": 0.0, "peak": 0.0, "label": label}
        return {"raw_mean": 0.0, "raw_max": 0.0, "raw_min": 0.0, "raw_range": 0.0}

    mean = sum(data) / len(data)
    maximum = max(data)
    minimum = min(data)

    if display:
        return {"avg": round(mean, 1), "peak": round(maximum, 1), "label": label}

    return {
        "raw_mean": mean,
        "raw_max": maximum,
        "raw_min": minimum,
        "raw_range": maximum - minimum,
    }


def compute_quality_score(cleaned_data):
    n_zeros = sum(1 for x in cleaned_data if x == 0)
    return 1.0 - (n_zeros / len(cleaned_data)) if cleaned_data else 0.0
