            except ConnectionError as e:
                # It may have failed after partial success in an earlier attempt
                existing = get(r["key"])
                if existing:
                    seq = existing["seq"]
                    break
                last_exc = e
                continue
        else:
            # failed after max_retries attempts at the batch level
            raise ConnectionError(f"failed to write {r['key']} after {max_retries} batch retries") from last_exc

        results.append({"key": r["key"], "seq": seq})
    return {"results": results, "final_seq": get_seq()}


