    existing = _invoice_index.get(idempotency_key)
    if existing is not None:
        return existing

    # Determine pricing version once for the whole invoice to ensure
    # all line items use the same pricing.
    pricing_version = get_pricing_version(use_new_pricing)

    total = 0
    lines = []
    for item in items:
        price = compute_price(item["base"], item["qty"], use_new_pricing)
        lines.append({"sku": item["sku"], "amount": price})
        total += price

    invoice = {
        "customer": customer,
        "lines": lines,
        "total": total,
        "pricing_version": pricing_version,
        "idempotency_key": idempotency_key,
    }

    # Mark audit and append only after the invoice is fully constructed.
    if is_enabled("audit_mode"):
        invoice["audit"] = True
        _invoices.append(invoice)

    # Record in idempotency index so subsequent retries return the same invoice
    # and do not cause duplicate side effects.
    _invoice_index[idempotency_key] = invoice

    return invoice


